EMBEDDED_INDEX_HTML = '<!doctype html>\n<html lang="en">\n  <head>\n    <meta charset="utf-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1">\n    <title>Xiaomi Daily Report Engine</title>\n    <style>\n:root {\n  --bg: #f6f7f9;\n  --surface: #ffffff;\n  --ink: #15171a;\n  --muted: #6b7280;\n  --line: #e5e7eb;\n  --brand: #ff6900;\n  --brand-dark: #d64d00;\n  --green: #15803d;\n  --blue: #2563eb;\n  --shadow: 0 18px 45px rgba(19, 24, 32, 0.08);\n}\n\n* {\n  box-sizing: border-box;\n}\n\n[hidden] {\n  display: none !important;\n}\n\nbody {\n  margin: 0;\n  min-height: 100vh;\n  background: var(--bg);\n  color: var(--ink);\n  font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;\n  letter-spacing: 0;\n}\n\nbutton,\ninput,\na {\n  font: inherit;\n}\n\n.app-shell {\n  min-height: 100vh;\n}\n\n.topbar {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 24px;\n  padding: 22px 30px;\n  background: #111111;\n  color: #ffffff;\n}\n\n.brand {\n  display: flex;\n  align-items: center;\n  gap: 14px;\n  min-width: 0;\n}\n\n.brand-mark {\n  display: grid;\n  place-items: center;\n  width: 48px;\n  height: 48px;\n  flex: 0 0 auto;\n  border-radius: 8px;\n  background: var(--brand);\n  color: #ffffff;\n  font-size: 22px;\n  font-weight: 800;\n}\n\nh1,\nh2,\np {\n  margin: 0;\n}\n\nh1 {\n  font-size: clamp(24px, 3vw, 34px);\n  line-height: 1.08;\n  font-weight: 760;\n}\n\nh2 {\n  margin-top: 4px;\n  font-size: 23px;\n  line-height: 1.2;\n}\n\n.brand p {\n  margin-top: 4px;\n  color: #d1d5db;\n  font-size: 14px;\n}\n\n.run-state {\n  min-width: 92px;\n  padding: 8px 12px;\n  border: 1px solid rgba(255, 255, 255, 0.18);\n  border-radius: 999px;\n  text-align: center;\n  color: #f9fafb;\n  background: rgba(255, 255, 255, 0.07);\n  font-size: 13px;\n  font-weight: 700;\n}\n\n.workspace {\n  display: grid;\n  grid-template-columns: minmax(300px, 380px) minmax(0, 1fr);\n  gap: 22px;\n  width: min(1480px, calc(100% - 40px));\n  margin: 24px auto;\n}\n\n.input-panel,\n.result-panel {\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  background: var(--surface);\n  box-shadow: var(--shadow);\n}\n\n.input-panel {\n  align-self: start;\n  padding: 22px;\n}\n\n.result-panel {\n  min-width: 0;\n  padding: 22px;\n}\n\n.panel-heading,\n.result-header {\n  display: flex;\n  align-items: flex-start;\n  justify-content: space-between;\n  gap: 18px;\n}\n\n.report-switch {\n  display: inline-flex;\n  gap: 3px;\n  margin-top: 12px;\n  padding: 3px;\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  background: #f3f4f6;\n}\n\n.report-tab {\n  min-height: 34px;\n  padding: 0 12px;\n  border: 0;\n  border-radius: 6px;\n  background: transparent;\n  color: var(--muted);\n  font-size: 13px;\n  font-weight: 800;\n  cursor: pointer;\n}\n\n.report-tab.active {\n  background: #ffffff;\n  color: var(--ink);\n  box-shadow: 0 1px 3px rgba(15, 23, 42, 0.1);\n}\n\n.eyebrow {\n  color: var(--brand-dark);\n  font-size: 12px;\n  font-weight: 800;\n  letter-spacing: 0;\n  text-transform: uppercase;\n}\n\n.default-list {\n  display: grid;\n  gap: 10px;\n  margin: 22px 0;\n}\n\n.file-status {\n  display: grid;\n  grid-template-columns: 10px 1fr;\n  align-items: start;\n  gap: 10px;\n  padding: 12px;\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  background: #fbfbfc;\n}\n\n.status-dot {\n  width: 10px;\n  height: 10px;\n  margin-top: 6px;\n  border-radius: 999px;\n  background: #9ca3af;\n}\n\n.status-dot.ready {\n  background: var(--green);\n}\n\n.status-dot.missing {\n  background: #dc2626;\n}\n\n.file-status strong,\n.upload-box strong {\n  display: block;\n  font-size: 14px;\n  line-height: 1.3;\n}\n\n.file-status small,\n.upload-box small {\n  display: block;\n  margin-top: 3px;\n  color: var(--muted);\n  font-size: 12px;\n  line-height: 1.35;\n  overflow-wrap: anywhere;\n}\n\n.report-form {\n  display: grid;\n  gap: 14px;\n}\n\n.upload-box {\n  display: grid;\n  grid-template-columns: 42px 1fr;\n  gap: 12px;\n  min-height: 74px;\n  padding: 14px;\n  border: 1px dashed #c8cdd5;\n  border-radius: 8px;\n  background: #ffffff;\n  cursor: pointer;\n  transition: border-color 160ms ease, background 160ms ease, transform 160ms ease;\n}\n\n.upload-box:hover {\n  border-color: var(--brand);\n  background: #fff8f3;\n  transform: translateY(-1px);\n}\n\n.upload-box input {\n  position: absolute;\n  width: 1px;\n  height: 1px;\n  overflow: hidden;\n  clip: rect(0, 0, 0, 0);\n}\n\n.upload-icon {\n  display: grid;\n  place-items: center;\n  width: 42px;\n  height: 42px;\n  border-radius: 8px;\n  background: #f3f4f6;\n}\n\nsvg {\n  width: 20px;\n  height: 20px;\n  fill: none;\n  stroke: currentColor;\n  stroke-width: 2;\n  stroke-linecap: round;\n  stroke-linejoin: round;\n}\n\n.primary-button,\n.secondary-button {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  gap: 9px;\n  min-height: 44px;\n  border-radius: 8px;\n  text-decoration: none;\n  font-weight: 800;\n  cursor: pointer;\n}\n\n.primary-button {\n  width: 100%;\n  border: 0;\n  background: var(--brand);\n  color: #ffffff;\n}\n\n.primary-button:hover {\n  background: var(--brand-dark);\n}\n\n.primary-button:disabled {\n  cursor: wait;\n  opacity: 0.7;\n}\n\n.secondary-button {\n  min-width: 98px;\n  padding: 0 13px;\n  border: 1px solid var(--line);\n  background: #ffffff;\n  color: var(--ink);\n}\n\n.secondary-button:not(.disabled):hover {\n  border-color: #c7ccd5;\n  background: #f9fafb;\n}\n\n.secondary-button.disabled {\n  pointer-events: none;\n  color: #9ca3af;\n  background: #f3f4f6;\n}\n\n.download-actions {\n  display: flex;\n  align-items: center;\n  justify-content: flex-end;\n  gap: 10px;\n}\n\n.summary-grid {\n  display: grid;\n  grid-template-columns: repeat(4, minmax(130px, 1fr));\n  gap: 12px;\n  margin-top: 22px;\n}\n\n.metric-tile {\n  min-height: 92px;\n  padding: 16px;\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  background: #fbfbfc;\n}\n\n.metric-tile small {\n  display: block;\n  min-height: 18px;\n  color: var(--muted);\n  font-size: 12px;\n  font-weight: 800;\n  text-transform: uppercase;\n}\n\n.metric-tile strong {\n  display: block;\n  margin-top: 10px;\n  font-size: clamp(22px, 3vw, 30px);\n  line-height: 1;\n}\n\n.metric-tile.accent {\n  border-color: #fed7aa;\n  background: #fff7ed;\n}\n\n.notice {\n  margin-top: 18px;\n  padding: 13px 14px;\n  border: 1px solid #dbeafe;\n  border-radius: 8px;\n  background: #eff6ff;\n  color: #1e3a8a;\n  font-size: 14px;\n  font-weight: 700;\n}\n\n.notice.error {\n  border-color: #fecaca;\n  background: #fff1f2;\n  color: #991b1b;\n}\n\n.table-wrap {\n  width: 100%;\n  max-height: calc(100vh - 332px);\n  min-height: 330px;\n  margin-top: 18px;\n  overflow: auto;\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  background: #ffffff;\n}\n\ntable {\n  width: 100%;\n  min-width: 720px;\n  border-collapse: collapse;\n  font-size: 13px;\n}\n\nth,\ntd {\n  padding: 11px 12px;\n  border-bottom: 1px solid var(--line);\n  text-align: left;\n  vertical-align: top;\n}\n\nth {\n  position: sticky;\n  top: 0;\n  z-index: 1;\n  background: #1f2937;\n  color: #ffffff;\n  font-weight: 800;\n}\n\ntd.numeric {\n  text-align: right;\n  font-variant-numeric: tabular-nums;\n}\n\ntr.total-row td {\n  background: #fff7ed;\n  font-weight: 800;\n}\n\ntr.grand-row td {\n  background: var(--brand);\n  color: #ffffff;\n  font-weight: 900;\n}\n\n@media (max-width: 920px) {\n  .topbar,\n  .workspace {\n    width: 100%;\n  }\n\n  .topbar {\n    align-items: flex-start;\n    padding: 18px;\n  }\n\n  .workspace {\n    grid-template-columns: 1fr;\n    margin: 16px 0;\n    padding: 0 14px 18px;\n  }\n\n  .summary-grid {\n    grid-template-columns: repeat(2, minmax(0, 1fr));\n  }\n}\n\n@media (max-width: 560px) {\n  .topbar {\n    flex-direction: column;\n  }\n\n  .brand {\n    align-items: flex-start;\n  }\n\n  .result-header {\n    flex-direction: column;\n  }\n\n  .download-actions {\n    width: 100%;\n    justify-content: stretch;\n  }\n\n  .secondary-button {\n    flex: 1;\n  }\n\n  .summary-grid {\n    grid-template-columns: 1fr;\n  }\n}\n\n</style>\n  </head>\n  <body>\n    <div class="app-shell">\n      <header class="topbar">\n        <div class="brand">\n          <div class="brand-mark" aria-hidden="true">mi</div>\n          <div>\n            <h1>Xiaomi Daily Report Engine</h1>\n            <p>Daily GWP and zonal report workspace</p>\n          </div>\n        </div>\n        <div class="run-state" id="runState">Ready</div>\n      </header>\n\n      <main class="workspace">\n        <aside class="input-panel" aria-label="Report inputs">\n          <div class="panel-heading">\n            <span class="eyebrow">Inputs</span>\n            <h2>Report Files</h2>\n          </div>\n\n          <div class="default-list" id="defaultList" aria-live="polite">\n            <div class="file-status">\n              <span class="status-dot"></span>\n              <div>\n                <strong>Upload Service Report</strong>\n              </div>\n            </div>\n          </div>\n\n          <form id="reportForm" class="report-form">\n            <input id="reportType" name="report_type" type="hidden" value="service">\n\n            <label class="upload-box" for="serviceFile" data-report-input="service">\n              <span class="upload-icon" aria-hidden="true">\n                <svg viewBox="0 0 24 24" role="img">\n                  <path d="M12 3v12m0-12 4 4m-4-4-4 4M5 15v4h14v-4"></path>\n                </svg>\n              </span>\n              <span>\n                <strong>Upload Service File</strong>\n                <small id="serviceFileName">Use local default or choose a CSV</small>\n              </span>\n              <input id="serviceFile" name="service_file" type="file" accept=".csv,text/csv">\n            </label>\n\n            <label class="upload-box" for="axioFile" data-report-input="channel" hidden>\n              <span class="upload-icon" aria-hidden="true">\n                <svg viewBox="0 0 24 24" role="img">\n                  <path d="M4 19h16M7 16V8m5 8V5m5 11v-6"></path>\n                </svg>\n              </span>\n              <span>\n                <strong>Upload Axio File</strong>\n                <small id="axioFileName">Use local default or choose a CSV</small>\n              </span>\n              <input id="axioFile" name="axio_file" type="file" accept=".csv,text/csv">\n            </label>\n\n            <label class="upload-box" for="retailFile" data-report-input="channel" hidden>\n              <span class="upload-icon" aria-hidden="true">\n                <svg viewBox="0 0 24 24" role="img">\n                  <path d="M4 7h16M4 12h16M4 17h16"></path>\n                </svg>\n              </span>\n              <span>\n                <strong>Upload Retail File</strong>\n                <small id="retailFileName">Use local default or choose a CSV</small>\n              </span>\n              <input id="retailFile" name="retail_file" type="file" accept=".csv,text/csv">\n            </label>\n\n            <button class="primary-button" id="generateButton" type="submit">\n              <svg viewBox="0 0 24 24" aria-hidden="true">\n                <path d="m5 12 5 5L20 7"></path>\n              </svg>\n              Generate Report\n            </button>\n          </form>\n        </aside>\n\n        <section class="result-panel" aria-label="Report results">\n          <div class="result-header">\n            <div>\n              <span class="eyebrow">Output</span>\n              <h2>Daily Report</h2>\n              <div class="report-switch" role="tablist" aria-label="Report view">\n                <button class="report-tab active" id="serviceReportTab" type="button" data-report="service">\n                  Service\n                </button>\n                <button class="report-tab" id="channelReportTab" type="button" data-report="channel">\n                  Retail + Axio\n                </button>\n              </div>\n            </div>\n            <div class="download-actions">\n              <a class="secondary-button disabled" id="downloadReport" href="#" aria-disabled="true">\n                <svg viewBox="0 0 24 24" aria-hidden="true">\n                  <path d="M12 3v12m0 0 4-4m-4 4-4-4M5 21h14"></path>\n                </svg>\n                Download Report\n              </a>\n            </div>\n          </div>\n\n          <div class="summary-grid" id="summaryGrid">\n            <div class="metric-tile">\n              <small>Paid Units</small>\n              <strong>0</strong>\n            </div>\n            <div class="metric-tile">\n              <small>Total GWP</small>\n              <strong>0</strong>\n            </div>\n            <div class="metric-tile">\n              <small>Regions</small>\n              <strong>0</strong>\n            </div>\n            <div class="metric-tile">\n              <small>Unmatched ASC</small>\n              <strong>0</strong>\n            </div>\n          </div>\n\n          <div class="notice" id="notice">\n            Generate a report to preview rows and unlock downloads.\n          </div>\n\n          <div class="table-wrap" id="tableWrap" hidden>\n            <table>\n              <thead id="previewHead"></thead>\n              <tbody id="previewBody"></tbody>\n            </table>\n          </div>\n        </section>\n      </main>\n    </div>\n\n    <script>\nconst form = document.querySelector("#reportForm");\nconst generateButton = document.querySelector("#generateButton");\nconst runState = document.querySelector("#runState");\nconst defaultList = document.querySelector("#defaultList");\nconst reportType = document.querySelector("#reportType");\nconst serviceFile = document.querySelector("#serviceFile");\nconst axioFile = document.querySelector("#axioFile");\nconst retailFile = document.querySelector("#retailFile");\nconst serviceFileName = document.querySelector("#serviceFileName");\nconst axioFileName = document.querySelector("#axioFileName");\nconst retailFileName = document.querySelector("#retailFileName");\nconst summaryGrid = document.querySelector("#summaryGrid");\nconst notice = document.querySelector("#notice");\nconst tableWrap = document.querySelector("#tableWrap");\nconst previewHead = document.querySelector("#previewHead");\nconst previewBody = document.querySelector("#previewBody");\nconst downloadReport = document.querySelector("#downloadReport");\nconst reportTabs = document.querySelectorAll(".report-tab");\n\nconst numberFormatter = new Intl.NumberFormat("en-IN");\nlet currentReports = {};\nlet activeReport = document.querySelector(".report-tab.active")?.dataset.report || "service";\nlet currentStatus = null;\n\nfunction setRunState(label) {\n  runState.textContent = label;\n}\n\nfunction formatBytes(bytes) {\n  if (!bytes) return "0 KB";\n  const units = ["B", "KB", "MB", "GB"];\n  const index = Math.min(Math.floor(Math.log(bytes) / Math.log(1024)), units.length - 1);\n  return `${(bytes / 1024 ** index).toFixed(index === 0 ? 0 : 1)} ${units[index]}`;\n}\n\nfunction escapeHtml(value) {\n  return String(value ?? "")\n    .replaceAll("&", "&amp;")\n    .replaceAll("<", "&lt;")\n    .replaceAll(">", "&gt;")\n    .replaceAll(\'"\', "&quot;")\n    .replaceAll("\'", "&#039;");\n}\n\nfunction renderFileStatus(label, status) {\n  const dotClass = status.exists ? "ready" : "missing";\n\n  return `\n    <div class="file-status">\n      <span class="status-dot ${dotClass}"></span>\n      <div>\n        <strong>${escapeHtml(label)}</strong>\n      </div>\n    </div>\n  `;\n}\n\nfunction renderSummary(summary = {}, reportKey = activeReport) {\n  const metrics = reportKey === "channel"\n    ? [\n        ["Total Units", summary.total_units ?? 0, "accent"],\n        ["Total GWP", summary.total_gwp ?? 0, "accent"],\n        ["AXIO Units", summary.axio_units ?? 0, ""],\n        ["Retail Units", summary.retail_units ?? 0, ""],\n        ["States", summary.states ?? 0, ""],\n        ["Stores", summary.stores ?? 0, ""],\n      ]\n    : [\n        ["Paid Units", summary.paid_rows ?? 0, "accent"],\n        ["Total GWP", summary.total_gwp ?? 0, "accent"],\n        ["Regions", summary.regions ?? summary.zones ?? 0, ""],\n        ["Unmatched ASC", summary.unmatched_rows ?? 0, ""],\n        ["Input Rows", summary.input_rows ?? 0, ""],\n        ["Service Centers", summary.service_centers ?? 0, ""],\n      ];\n\n  summaryGrid.innerHTML = metrics\n    .map(([label, value, className]) => `\n      <div class="metric-tile ${className}">\n        <small>${escapeHtml(label)}</small>\n        <strong>${numberFormatter.format(value)}</strong>\n      </div>\n    `)\n    .join("");\n}\n\nfunction renderPreview(columns, rows) {\n  previewHead.innerHTML = `\n    <tr>\n      ${columns.map((column) => `<th>${escapeHtml(column)}</th>`).join("")}\n    </tr>\n  `;\n\n  previewBody.innerHTML = rows\n    .map((row) => {\n      const isGrand = row.Region === "Grand Total" || row.Zone === "Grand Total" || row.State === "Grand Total";\n      const isTotal = isGrand\n        || String(row.Region || "").endsWith("Total")\n        || String(row.Zone || "").endsWith("Total")\n        || String(row.State || "").endsWith("Total")\n        || String(row.DistributorName || "").endsWith("Total");\n      const rowClass = isGrand ? "grand-row" : isTotal ? "total-row" : "";\n      return `\n        <tr class="${rowClass}">\n          ${columns\n            .map((column) => {\n              const value = row[column] ?? "";\n              const isNumeric = column.includes("Unit") || column.includes("GWP");\n              const text = isNumeric && value !== "" ? numberFormatter.format(value) : value;\n              return `<td class="${isNumeric ? "numeric" : ""}">${escapeHtml(text)}</td>`;\n            })\n            .join("")}\n        </tr>\n      `;\n    })\n    .join("");\n\n  tableWrap.hidden = false;\n}\n\nfunction setDownloadEnabled(link, downloadValue, enabled) {\n  const directHref = enabled && String(downloadValue || "").startsWith("/") ? downloadValue : "#";\n  link.href = directHref;\n  link.dataset.downloadValue = enabled ? String(downloadValue || "") : "";\n  link.classList.toggle("disabled", !enabled);\n  link.setAttribute("aria-disabled", enabled ? "false" : "true");\n}\n\nfunction setDownloads(downloads = {}, reportKey = activeReport) {\n  const downloadValue = reportKey === "channel"\n    ? downloads.channel_report\n    : downloads.final_report;\n  setDownloadEnabled(downloadReport, downloadValue, Boolean(downloadValue));\n}\n\nfunction renderDefaultStatus() {\n  if (!currentStatus) return;\n\n  const defaults = currentStatus.defaults;\n  const rows = activeReport === "channel"\n    ? [\n        renderFileStatus("Upload Axio Report", defaults.axio),\n        renderFileStatus("Upload Retail Report", defaults.retail),\n      ]\n    : [\n        renderFileStatus("Upload Service Report", defaults.service),\n      ];\n\n  defaultList.innerHTML = rows.join("");\n}\n\nfunction setVisibleInputs(reportKey) {\n  document.querySelectorAll("[data-report-input]").forEach((element) => {\n    const isVisible = element.dataset.reportInput === reportKey;\n    element.hidden = !isVisible;\n    element.setAttribute("aria-hidden", isVisible ? "false" : "true");\n  });\n\n  reportType.value = reportKey;\n}\n\nfunction switchReport(reportKey, options = {}) {\n  activeReport = reportKey;\n  setVisibleInputs(reportKey);\n  renderDefaultStatus();\n\n  reportTabs.forEach((tab) => {\n    const isActive = tab.dataset.report === reportKey;\n    tab.classList.toggle("active", isActive);\n    tab.setAttribute("aria-selected", isActive ? "true" : "false");\n  });\n\n  const report = currentReports[reportKey];\n  if (!report) {\n    renderSummary({}, reportKey);\n    if (!options.keepPreview) {\n      tableWrap.hidden = true;\n    }\n    setDownloads({}, reportKey);\n    return;\n  }\n\n  renderSummary(report.summary, reportKey);\n  renderPreview(report.columns, report.preview);\n  setDownloads(report.downloads, reportKey);\n}\n\nfunction showNotice(message, isError = false) {\n  notice.textContent = message;\n  notice.classList.toggle("error", isError);\n}\n\nfunction getDownloadFilename(response, fallbackName) {\n  const contentDisposition = response.headers.get("content-disposition") || "";\n  const match = /filename="?([^"]+)"?/i.exec(contentDisposition);\n  return match?.[1] || fallbackName;\n}\n\nasync function triggerGeneratedDownload(downloadKey) {\n  const fallbackNames = {\n    final_report: "final_report.xlsx",\n    zonal_report: "zonal_report.xlsx",\n    channel_report: "final_channel_report.xlsx",\n  };\n\n  setRunState("Preparing");\n  showNotice("Preparing download...");\n\n  const formData = new FormData(form);\n  formData.set("report_type", activeReport);\n  formData.set("download_key", downloadKey);\n\n  const response = await fetch("/api/download", {\n    method: "POST",\n    body: formData,\n  });\n\n  if (!response.ok) {\n    const contentType = response.headers.get("content-type") || "";\n    if (contentType.includes("application/json")) {\n      const data = await response.json();\n      throw new Error(data.error || "Download failed.");\n    }\n    throw new Error(await response.text() || "Download failed.");\n  }\n\n  const blob = await response.blob();\n  const filename = getDownloadFilename(response, fallbackNames[downloadKey] || "report.xlsx");\n  const objectUrl = URL.createObjectURL(blob);\n  const anchor = document.createElement("a");\n  anchor.href = objectUrl;\n  anchor.download = filename;\n  document.body.appendChild(anchor);\n  anchor.click();\n  anchor.remove();\n  URL.revokeObjectURL(objectUrl);\n}\n\nasync function loadStatus() {\n  const response = await fetch("/api/status", { cache: "no-store" });\n  currentStatus = await response.json();\n  renderDefaultStatus();\n\n  const downloads = {};\n  if (currentStatus.outputs.final_report.exists) {\n    downloads.final_report = "/download/final_report.xlsx";\n  }\n  if (currentStatus.outputs.zonal_report.exists) {\n    downloads.zonal_report = "/download/zonal_report.xlsx";\n  }\n  if (currentStatus.outputs.channel_report.exists) {\n    downloads.channel_report = "/download/final_channel_report.xlsx";\n  }\n  setDownloads(downloads, activeReport);\n}\n\nserviceFile.addEventListener("change", () => {\n  serviceFileName.textContent = serviceFile.files[0]?.name || "Use local default or choose a CSV";\n});\n\naxioFile.addEventListener("change", () => {\n  axioFileName.textContent = axioFile.files[0]?.name || "Use local default or choose a CSV";\n});\n\nretailFile.addEventListener("change", () => {\n  retailFileName.textContent = retailFile.files[0]?.name || "Use local default or choose a CSV";\n});\n\nreportTabs.forEach((tab) => {\n  tab.addEventListener("click", () => {\n    switchReport(tab.dataset.report);\n  });\n});\n\ndownloadReport.addEventListener("click", async (event) => {\n  const downloadValue = downloadReport.dataset.downloadValue || "";\n  const isDisabled = downloadReport.getAttribute("aria-disabled") === "true";\n  if (isDisabled || downloadValue === "") {\n    event.preventDefault();\n    return;\n  }\n\n  if (downloadValue.startsWith("/")) {\n    return;\n  }\n\n  event.preventDefault();\n  try {\n    await triggerGeneratedDownload(downloadValue);\n    showNotice("Downloaded report.");\n    setRunState("Complete");\n  } catch (error) {\n    showNotice(error.message, true);\n    setRunState("Error");\n  }\n});\n\nform.addEventListener("submit", async (event) => {\n  event.preventDefault();\n\n  // Vercel 4.5MB limit check\n  const files = [serviceFile, axioFile, retailFile];\n  let totalSize = 0;\n  for (const f of files) {\n    if (f.files[0]) totalSize += f.files[0].size;\n  }\n\n  if (totalSize > 4.4 * 1024 * 1024) {\n    showNotice("Total upload size exceeds 4.5MB (Vercel limit). Please use smaller files.", true);\n    return;\n  }\n\n  generateButton.disabled = true;\n  setRunState("Running");\n  showNotice("Generating report...");\n\n  try {\n    const response = await fetch("/api/generate", {\n      method: "POST",\n      body: new FormData(form),\n    });\n\n    const data = await response.json();\n    if (!response.ok) {\n      throw new Error(data.error || "Report generation failed.");\n    }\n\n    currentReports = { ...currentReports, ...(data.reports || {}) };\n    switchReport(data.active_report || "service");\n    showNotice(`Generated ${data.summary.total_units} units at ${data.summary.generated_at}.`);\n    setRunState("Complete");\n  } catch (error) {\n    showNotice(error.message, true);\n    setRunState("Error");\n  } finally {\n    generateButton.disabled = false;\n  }\n});\n\nswitchReport(activeReport, { keepPreview: true });\nrenderSummary({}, activeReport);\nloadStatus().catch(() => {\n  showNotice("Could not read local file status.", true);\n});\n\n</script>\n  </body>\n</html>\n'
